// // This module reads a 1-bit input signal and provides a 1-bit output signal. The output signal reflects the state of the input signal after a falling edge of the clock signal, with an enable signal to indicate when the output should be updated. If the enable signal is high, the output should hold its previous state.
module gpio_controller(  
    input wire clk,  
    input wire enable,  
    input wire gpio_in,  
    output reg gpio_out  
);  
    always @(posedge clk) begin  
        if (enable)  
            gpio_out <= gpio_in;  
    end  
endmodule
